#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#define MAXN 100005
#define MAXM 105
typedef struct Node{
    int val;
    int childNum;
    struct Node** child;
}Node;
Node* newNode(int val) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->childNum = 0;
    node->child = NULL;
    return node;
}
void addNode(Node* parent, Node* child) {
    parent->childNum++;
    parent->child = (Node**)realloc(parent->child, parent->childNum * sizeof(Node*));
    parent->child[parent->childNum - 1] = child;
}
int minCost(Node* root, int* nodes, int M, int x, int y) {
    if (M == 0) return 0;
    int min = nodes[0] * root->val;
    if (root->childNum >= x) min += y;
    int minChild = INT_MAX;
    for (int i = 0; i < root->childNum; i++) {
        int cost = minCost(root->child[i], nodes + 1, M - 1, x, y);
        if (cost < minChild) minChild = cost;
    }
    if (minChild != INT_MAX) min += minChild;
    return min;
}
int main() {
    int N;
    scanf("%d", &N);
    Node* root = newNode(0);
    Node** nodes = (Node**)malloc(N * sizeof(Node*));
    for (int i = 0; i < N; i++) {
        int val;
        scanf("%d", &val);
        nodes[i] = newNode(val);
        if (i == 0) root = nodes[i];
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addNode(nodes[u - 1], nodes[v - 1]);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int M, x, y;
        scanf("%d %d %d", &M, &x, &y);
        int* values = (int*)malloc(M * sizeof(int));
        for (int j = 0; j < M; j++) {
            scanf("%d", &values[j]);
        }
        printf("%d\n", minCost(root, values, M, x, y));
        free(values);
    }
    for (int i = 0; i < N; i++) {
        free(nodes[i]->child);
        free(nodes[i]);
    }
    free(nodes);
    return 0;
}

