#define MAXN 100005
#define MAXM 105
struct Node {
    int val;
    vector<Node*> child;
    Node(int val) : val(val) {}
};
int minCost(Node* root, vector<int>& nodes, int M, int x, int y) {
    if (M == 0) return 0;
    int min = nodes[0] * root->val;
    if (root->child.size() >= x) min += y;
    int minChild = INT_MAX;
    for (auto child : root->child) {
        vector<int> newNodes(nodes.begin() + 1, nodes.end());
        int cost = minCost(child, newNodes, M - 1, x, y);
        if (cost < minChild) minChild = cost;
    }
    if (minChild != INT_MAX) min += minChild;
    return min;
}
int main() {
    int N;
    cin >> N;
    Node* root = new Node(0);
    Node** nodes = new Node*[N];
    for (int i = 0; i < N; i++) {
        int val;
        cin >> val;
        nodes[i] = new Node(val);
        if (i == 0) root = nodes[i];
    }
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        cin >> u >> v;
        nodes[u - 1]->child.push_back(nodes[v - 1]);
    }
    int Q;
    cin >> Q;
    for (int i = 0; i < Q; i++) {
        int M, x, y;
        cin >> M >> x >> y;
        vector<int> values(M);
