import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static class Node {
        int val;
        List<Node> child;
        Node(int val) {
            this.val = val;
            this.child = new ArrayList<>();
        }
    }
    static int minCost(Node root, int[] nodes, int M, int x, int y) {
        if (M == 0) return 0;
        int min = nodes[0] * root.val;
        if (root.child.size() >= x) min += y;
        int minChild = Integer.MAX_VALUE;
        for (Node child : root.child) {
            int[] newNodes = new int[M - 1];
            System.arraycopy(nodes, 1, newNodes, 0, M - 1);
            int cost = minCost(child, newNodes, M - 1, x, y);
            if (cost < minChild) minChild = cost;
        }
        if (minChild != Integer.MAX_VALUE) min += minChild;
        return min;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Node root = new Node(0);
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            int val = scanner.nextInt();
            nodes[i] = new Node(val);
            if (i == 0) root = nodes[i];
        }
        for (int i = 0; i < N - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            nodes[u - 1].child.add(nodes[v - 1]);
        }
        int Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            int M = scanner.nextInt();
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            int[] values = new int[M];
            for (int j = 0; j < M; j++) {
                values[j] = scanner.nextInt();
            }
            System.out.println(minCost(root, values, M, x, y));
        }
    }
}

